mapper.insert:
/* wms-master-asrt-sql-oracle.xml - insertInterfaceAsrt */
INSERT INTO TWORK_INTF_ASRT_RCV (
	   CTKEY			/* 센터코드 */
	 , OWKEY			/* 화주코드 */
	 , ASRTMASICKEY		/* 아소트모상품코드 */
	 , ASRTDTICKEY		/* 아소트자상품코드 */
	 , QTY				/* 수량 */
	 , ICCOLOR			/* 색상 */
	 , ICDESIGN			/* 디자인 */
	 , ICCHRT			/* 캐릭터 */
	 , ICIMGURL			/* 상품이미지URL */
	 , DELYN			/* 삭제여부 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{asrtrepkey}
	 , #{asrtkey}
	 , #{qty}
	 , #{iccolor}
	 , #{icdesign}
	 , #{icchrt}
	 , #{icimgurl}
	 , #{delyn}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-asrt-sql-oracle.xml - insertTworkMstAsrt */
INSERT INTO TWORK_MST_ASRT (
	   CTKEY			/* 센터 코드 */
	 , OWKEY			/* 화주 코드 */
	 , ASRTMASICKEY		/* 아소트 모상품코드 */
	 , ASRTDTICKEY		/* 아소트 자상품코드 */
	 , ASRTNM			/* 상품명 */
	 , ASRTMASQTY		/* 아소트모상품수량 */
	 , QTY				/* 수량 */
	 , COLOR			/* 색상 */
	 , DESIGN			/* 디자인 */
	 , CHRT				/* 캐릭터 */
	 , IMGURL			/* 이미지URL */
	 , DELYN			/* 삭제여부 */
	 , INSERTDATE		/* 입력 일시 */
	 , INSERTURKEY		/* 입력 사용자 ID */
	 , UPDATEDATE		/* 수정 일시 */
	 , UPDATEURKEY		/* 수정 사용자 ID */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{asrtrepkey}
	 , #{asrtkey}
	 , (SELECT ICNM FROM TWORK_MST_IC WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND ICKEY = #{asrtkey})
	 , (SELECT ICUNITQTY FROM TWORK_MST_ICUTXTYPE WHERE CTKEY = #{ctkey} AND OWKEY = #{owkey} AND ICKEY = #{asrtrepkey} AND ICUNITTYPECD = 'INN')
	 , #{qty}
	 , #{iccolor}
	 , #{icdesign}
	 , #{icchrt}
	 , #{icimgurl}
	 , COALESCE(#{delyn}, 'N')
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-asrt-sql-oracle.xml - insertInterfaceAsrtRenewal */
INSERT INTO TWORK_INTF_ASRT_RENEW_RCV (
	   CTKEY			/* 센터코드 */
	 , OWKEY			/* 화주코드 */
	 , ISTREGDATE		/* 지시등록일자 */
	 , BFCHGICKEY		/* 변경전상품코드 */
	 , AFCHGICKEY		/* 변경후상품코드 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{istregdate}
	 , #{bfchgickey}
	 , #{afchgickey}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-asrt-sql-oracle.xml - insertTworkInfoAsrtRenew */
INSERT INTO TWORK_INFO_ASRT_RENEW (
	   CTKEY			/* 센터코드 */
	 , OWKEY			/* 화주코드 */
	 , BFCHGICKEY		/* 변경전상품코드 */
	 , AFCHGICKEY		/* 변경후상품코드 */
	 , WKISTDATE		/* 작업지시일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력사용자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정사용자 */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{bfchgickey}
	 , #{afchgickey}
	 , #{istregdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )
